load("lab4_exp1_data.mat")

% EKV Parameters Plot
[Is_Q1, VT_Q1, kappa_Q1] = ekvfit(Vg_Q1, I_circuit_Q1, 1e-4) %[output:93769784] %[output:4c177ed0] %[output:2ac56fbd]
[Is_Q2, VT_Q2, kappa_Q2] = ekvfit(Vg_Q2, I_circuit_Q2, 1e-4) %[output:31fb665a] %[output:2c477cec] %[output:66fb5bf4]
[Is_Q3, VT_Q3, kappa_Q3] = ekvfit(Vg_Q3, I_circuit_Q3, 1e-4) %[output:09bf060d] %[output:029ecbe4] %[output:35178b10]
[Is_Q4, VT_Q4, kappa_Q4] = ekvfit(Vg_Q4, I_circuit_Q4, 1e-4) %[output:7b6ec87d] %[output:541eec90] %[output:8d5de07f]

numerical_ekv_prediction_Q1 = Is_Q1 .* (log(1 + exp(kappa_Q1 .* (Vg_Q1 - VT_Q1) ./ (2 .* 0.0258)))).^2;

figure(); %[output:2b220554]
semilogy(Vg_Q1, I_circuit_Q1, '.', DisplayName='Measured Data - MOSFET 1') %[output:2b220554]
hold on; %[output:2b220554]
semilogy(Vg_Q2, I_circuit_Q2, '.', DisplayName='Measured Data - MOSFET 2') %[output:2b220554]
semilogy(Vg_Q3, I_circuit_Q3, '.', DisplayName='Measured Data - MOSFET 3') %[output:2b220554]
semilogy(Vg_Q4, I_circuit_Q4, '.', DisplayName='Measured Data - MOSFET 4') %[output:2b220554]

semilogy(Vg_Q1, numerical_ekv_prediction_Q1, DisplayName='EKV Model Prediction - MOSFET 1') %[output:2b220554]

xlabel('Gate Voltage (V)') %[output:2b220554]
ylabel('Drain-Source Current (A)') %[output:2b220554]
title('Current-Voltage Characteristics of MOSFETs') %[output:2b220554]
legend(Location='southoutside') %[output:2b220554]

% Variation between Transistors
I_circuit_All = [I_circuit_Q1; I_circuit_Q2; I_circuit_Q3; I_circuit_Q4];
I_circuit_Avg = mean(I_circuit_All, 1);

figure(); %[output:2b7bf909]
semilogx(I_circuit_Avg, ((I_circuit_Q1 - I_circuit_Avg) ./ I_circuit_Avg) .* 100, '.', DisplayName='MOSFET 1') %[output:2b7bf909]
hold on %[output:2b7bf909]
semilogx(I_circuit_Avg, ((I_circuit_Q2 - I_circuit_Avg) ./ I_circuit_Avg) .* 100, '.', DisplayName='MOSFET 2') %[output:2b7bf909]
semilogx(I_circuit_Avg, ((I_circuit_Q3 - I_circuit_Avg) ./ I_circuit_Avg) .* 100, '.', DisplayName='MOSFET 3') %[output:2b7bf909]
semilogx(I_circuit_Avg, ((I_circuit_Q4 - I_circuit_Avg) ./ I_circuit_Avg) .* 100, '.', DisplayName='MOSFET 4') %[output:2b7bf909]

xlabel('Average Drain-Source Current (A)') %[output:2b7bf909]
ylabel('Percent Variation in Drain-Source Current (%)') %[output:2b7bf909]
title('Variation in Current Characteristics of MOSFETs') %[output:2b7bf909]
legend(Location='southoutside') %[output:2b7bf909]

% Transconductance Gain
transconductance_gain_Q1 = (diff(I_circuit_Q1)) ./ (diff(Vg_Q1));
S = 0.8;
transconductance_gain_prediction_Q1 = (kappa_Q1 / 0.025) .* sqrt(S .* Is_Q1 .* I_circuit_Q1) .* (1 - exp(-sqrt(I_circuit_Q1 ./ (S * Is_Q1))));

figure() %[output:9fdd83b5]
loglog(I_circuit_Q1(1:end-1), transconductance_gain_Q1, '.', DisplayName='MOSFET 1') %[output:9fdd83b5]
hold on %[output:9fdd83b5]
loglog(I_circuit_Q1, transconductance_gain_prediction_Q1, DisplayName='EKV Model Prediction - MOSFET 1') %[output:57fab3ca] %[output:9fdd83b5]

xlabel('Drain-Source Current (A)') %[output:9fdd83b5]
ylabel(['Transconductance Gain (', char(8487), ')']) %[output:9fdd83b5]
title('Transconductance Gain of MOSFET') %[output:9fdd83b5]
legend(Location='southoutside') %[output:9fdd83b5] %[output:9593d874] %[output:33466006] %[output:54d9259f] %[output:3e6308f1] %[output:2f32b9ee]

